"use client";

import ThemeToggle from "@/components/theme-toggle";
import { cn } from "@/lib/utils";
import { HomeIcon, MenuIcon } from "lucide-react";
import { Inter } from "next/font/google";
import Link from "next/link";
import { usePathname } from "next/navigation";
import "./globals.css";
import Script from "next/script";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { useState } from "react";

const inter = Inter({ subsets: ["latin"] });

// export const metadata: Metadata = {
//   title: "Create Next App",
//   description: "Generated by create next app",
// };

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const pathname = usePathname();
  const [queryClient] = useState(() => new QueryClient());

  return (
    <html lang="en" className={cn("antialiased", inter.className)}>
      <Script src="/daisy-multiselect.js" strategy="afterInteractive"></Script>

      <body>
        <div className="drawer lg:drawer-open">
          <input id="my-drawer" type="checkbox" className="drawer-toggle" />
          <div className="drawer-content">
            <nav className="navbar w-full bg-base-100 shadow sticky top-0 z-10">
              <div className="navbar-start">
                <label
                  htmlFor="my-drawer"
                  aria-label="open sidebar"
                  className="btn btn-square btn-ghost lg:hidden"
                >
                  <MenuIcon />
                </label>
              </div>
              <div className="navbar-center">Navbar Title</div>
              <div className="navbar-end">
                <ThemeToggle />
              </div>
            </nav>

            <div className="p-4">
              <QueryClientProvider client={queryClient}>
                {children}
              </QueryClientProvider>
            </div>
          </div>

          <div className="drawer-side">
            <label
              htmlFor="my-drawer"
              aria-label="close sidebar"
              className="drawer-overlay"
            ></label>

            <ul className="menu bg-base-200 min-h-full w-64">
              <li>
                <button>
                  <HomeIcon className="w-4" />
                  <span className="">Home</span>
                </button>
              </li>
              <li>
                <details open={pathname.startsWith("/ui")}>
                  <summary>UI Elements</summary>
                  <ul>
                    <li>
                      <Link
                        href="/ui/general"
                        className={
                          pathname === "/ui/general" ? "menu-active" : ""
                        }
                      >
                        General
                      </Link>
                    </li>
                    <li>
                      <Link
                        href="/ui/buttons"
                        className={
                          pathname === "/ui/buttons" ? "menu-active" : ""
                        }
                      >
                        Buttons
                      </Link>
                    </li>
                  </ul>
                </details>
              </li>
              <li>
                <Link
                  href="/forms"
                  className={pathname === "/forms" ? "menu-active" : ""}
                >
                  <HomeIcon className="w-4" />
                  <span className="">Forms</span>
                </Link>
              </li>
            </ul>
          </div>
        </div>
      </body>
    </html>
  );
}
